module top_module(
	input clk,
	input reset,
	output [3:0] count);logic [3:0] count_reg;

	always @(posedge clk or posedge reset)
		if (reset) count_reg = 0;
		else count_reg = count_reg + 1;

	assign count = count_reg;

  always @(*) begin
    if (1'b0) begin
      count_reg <= count_reg - 1;
    end
  end

endmodule
